"""Activity: Struct Layout Bingo

Measure struct sizes and field offsets to discover how the compiler inserts padding -- and how #pragma pack changes everything.
"""
import os, shutil, subprocess, sys, tempfile, zipfile
import hashlib as _hl, hmac as _hm

SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
REPO_ZIP   = os.path.join(SCRIPT_DIR, 'repo.zip')

_SALT      = bytes.fromhex("a3f1b2c4d5e6f7a8b9c0d1e2f3a4b5c6")
_KDF_ITERS = 100000
_BLOB      = "ba5810365dda89ead170ee56229c976e383cbc4a8647cb46d5330d7061c309f7fbe3852808a780296b060e59f95d8fccdc258343eee17bbeff068b67"

def _decrypt(key_str):
    key  = _hl.pbkdf2_hmac('sha256', key_str.encode(), _SALT, _KDF_ITERS)
    blob = bytes.fromhex(_BLOB)
    ct, mac = blob[:-32], blob[-32:]
    if not _hm.compare_digest(mac, _hm.new(key, ct, _hl.sha256).digest()):
        return None
    ks, i, stream = b'', 0, b''
    while len(stream) < len(ct):
        stream += _hl.sha256(key + i.to_bytes(4, 'little')).digest()
        i += 1
    return bytes(a ^ b for a, b in zip(ct, stream)).decode()

_LINE_WIDTH = 70

def _banner(title):
    print('=' * _LINE_WIDTH)
    pad = (_LINE_WIDTH - len(title) - 2) // 2
    print(' ' * pad + ' ' + title + ' ' * pad)
    print('=' * _LINE_WIDTH)

def _hr():
    print('-' * _LINE_WIDTH)

def _show_passphrase(passphrase):
    print()
    _hr()
    print(f'  Passphrase: {passphrase}')
    _hr()
    print()

def die(msg):
    print(f'error: {msg}', file=sys.stderr)
    sys.exit(1)

def _build(repo_dir):
    r = subprocess.run(['make'], capture_output=True, text=True, cwd=repo_dir)
    return r.returncode == 0, r.stderr

def _run_lab(repo_dir):
    binary = os.path.join(repo_dir, 'layout_lab')
    if not os.path.isfile(binary):
        return None, 'layout_lab binary not found -- run make first'
    try:
        r = subprocess.run([binary], capture_output=True, text=True, timeout=10, cwd=repo_dir)
        return r.stdout.strip(), None
    except subprocess.TimeoutExpired:
        return None, 'timeout'
    except Exception as e:
        return None, str(e)

def main():
    if not os.path.isfile(REPO_ZIP):
        die('repo.zip not found.')

    work_dir = tempfile.mkdtemp(prefix='struct-layout-bingo-')
    with zipfile.ZipFile(REPO_ZIP, 'r') as zf:
        zf.extractall(work_dir)
    entries = os.listdir(work_dir)
    if len(entries) != 1:
        shutil.rmtree(work_dir, ignore_errors=True)
        die('unexpected zip structure')
    repo_dir = os.path.join(work_dir, entries[0])

    banner_text = """
      ============================================================
       Activity: Struct Layout Bingo
      ============================================================

       Step 1 -- read the struct definitions at the top of layout_lab.cpp
         On paper, draw each struct as a row of boxes.
         Label each box with its field name and byte count.
         Mark where you think padding bytes go.
       
       Step 2 -- fill in TODO 1 (sizeof for all four structs)
         printf("sizeof(Unpacked) = %zu\n", sizeof(Unpacked));
         Do the same for Packed, Reordered, and Simple.
       
       Step 3 -- fill in TODO 2 (offsetof for Unpacked fields a, b, c, d)
         printf("offsetof(Unpacked, a) = %zu\n", offsetof(Unpacked, a));
         Compare the offsets to your paper drawing.
         Do the padding gaps match what you predicted?
       
       Step 4 -- fill in TODO 3 (offsetof for Packed fields a, b, c, d)
         Notice how #pragma pack(push, 1) eliminates all gaps.
       
       Step 5 -- fill in TODO 4 and TODO 5 (Reordered and Simple)
         Reordered uses field order: d, b, a, c
         Simple uses field: z
       
       Step 6 -- build and run
         make
         ./layout_lab
         Compare the output to your paper drawing.
         If they differ, update your drawing and understand why.
       
       Step 7 -- exit when your output matches your expectations
         exit
      ============================================================

    """
    rcfile = tempfile.NamedTemporaryFile(mode='w', suffix='.rc', delete=False)
    rcfile.write(
        'PS1=\'\\u@struct-layout-bingo:\\W\\$ \'\n'
        f'cd "{repo_dir}"\n'
        "cat << \'BANNER\'\n" + banner_text + "\nBANNER\n"
    )
    rcfile.close()

    shell = os.environ.get('SHELL', '/bin/bash')

    try:
        while True:
            subprocess.run([shell, '--rcfile', rcfile.name])

            print()
            _banner('Activity: Struct Layout Bingo -- Checking Your Work')
            print()

            build_ok, build_err = _build(repo_dir)
            if not build_ok:
                print('  make failed.  Fix the compilation errors first:')
                for line in build_err.strip().splitlines()[:10]:
                    print(f'    {line}')
                print()
                try:
                    again = input('  Try again? [y/n] ').strip().lower()
                except (EOFError, KeyboardInterrupt):
                    print()
                    break
                if again == 'y':
                    print()
                    continue
                break

            output, err = _run_lab(repo_dir)
            if output is None:
                print(f'  Could not run layout_lab: {err}')
                print()
                try:
                    again = input('  Try again? [y/n] ').strip().lower()
                except (EOFError, KeyboardInterrupt):
                    print()
                    break
                if again == 'y':
                    print()
                    continue
                break

            passphrase = _decrypt(output)
            if passphrase is not None:
                _show_passphrase(passphrase)
                break

            print('  layout_lab ran, but the output does not match the expected format.')
            print('  Make sure every printf uses the exact format shown in the comments.')
            print()
            print('  Your output:')
            for line in output.splitlines()[:5]:
                print(f'    {line}')
            if len(output.splitlines()) > 5:
                print(f'    ... ({len(output.splitlines())} lines total)')
            print()
            try:
                again = input('  Try again? [y/n] ').strip().lower()
            except (EOFError, KeyboardInterrupt):
                print()
                break
            if again == 'y':
                print()
                continue
            break

    finally:
        try:
            os.remove(rcfile.name)
        except OSError:
            pass
        shutil.rmtree(work_dir, ignore_errors=True)


if __name__ == '__main__':
    main()
